from __future__ import annotations

import html

from fastapi.responses import HTMLResponse


def _document(title: str, body: str) -> HTMLResponse:
    return HTMLResponse(f"<!doctype html><html lang='en'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>{html.escape(title)}</title><style>{_css()}</style></head><body>{body}<script>{_js()}</script></body></html>")


def project_page(title: str, project_name: str, route: str = "/chat") -> HTMLResponse:
    name = html.escape(project_name)
    body = f"""
    <div class="app" data-page="{html.escape(route)}">
      <aside class="sidebar">
        <div class="brand"><span class="brand-mark">L</span><div><strong>Laplace</strong><small>Local research assistant</small></div></div>
        <div class="project-label">PROJECT</div><div id="project-name" class="project-name">{name}</div>
        <button id="new-chat" class="primary full">＋ New chat</button>
        <input id="conversation-filter" class="search-input" placeholder="Search conversations" aria-label="Search conversations">
        <div id="conversation-list" class="conversation-list" aria-label="Conversations"></div>
        <div class="sidebar-section"><div class="project-label">COLLECTIONS</div><div id="collections" class="collections"></div></div>
        <label class="mode-label" for="mode">Mode</label><select id="mode"><option>ASK</option><option>SEARCH</option><option>WRITE</option><option>RESEARCH</option><option>GENERAL</option></select>
        <nav class="nav"><a href="/chat" class="active">Chat</a><a href="/library">Library</a><a href="/research">Research</a><a href="/downloads">Downloads</a><a href="/settings">Settings</a><a href="/dashboard">System status</a></nav>
        <div class="privacy">● Localhost only<br><span>Ollama · qwen3:4b</span></div>
      </aside>
      <main class="main">
        <header class="topbar"><div><div class="eyebrow">{html.escape(title.upper())}</div><h1 id="conversation-title">New chat</h1></div><div class="top-actions"><span id="grounding-badge" class="badge">ASK · GROUNDED</span><button id="export" class="icon-button" title="Export conversation">⇩</button></div></header>
        <section id="messages" class="messages" aria-live="polite"><div class="empty-state"><div class="empty-logo">L</div><h2>Local, evidence-grounded research assistant</h2><p>Ask about indexed documents, inspect exact page evidence, or draft with provenance.</p><div class="suggestions"><button data-suggestion="Summarize the main contributions in MyWorks">Summarize the main contributions in MyWorks</button><button data-suggestion="Compare MyWorks with MyTopics">Compare MyWorks with MyTopics</button><button data-suggestion="Find papers about SRAM-CIM">Find papers about SRAM-CIM</button><button data-suggestion="Inspect unsupported claims">Inspect unsupported claims</button></div></div></section>
        <section id="secondary-page" class="secondary-page hidden"></section>
        <div id="status-line" class="status-line" role="status"></div>
        <form id="composer" class="composer"><textarea id="prompt" rows="2" placeholder="Ask a grounded question…" aria-label="Message"></textarea><div class="composer-footer"><span class="hint">Enter to send · Shift+Enter for a new line</span><div><button type="button" id="stop" class="secondary hidden">Stop</button><label class="attach">＋<input id="attachment" type="file" accept=".pdf,.txt,.md,.csv,.json" hidden></label><button class="send" type="submit">Send ↗</button></div></div></form>
      </main>
      <aside id="evidence-panel" class="evidence-panel"><div class="panel-heading"><span>Evidence</span><button id="close-evidence" class="icon-button">×</button></div><div id="evidence-content" class="evidence-content"><div class="evidence-empty">Select a citation to inspect its retrieved passage.</div></div></aside>
    </div>
    """
    return _document(f"Laplace · {title}", body)


def offline_dashboard(project_name: str = "") -> HTMLResponse:
    name = html.escape(project_name or "Current project")
    body = f"""
    <div class="dashboard"><div class="dashboard-header"><div class="brand"><span class="brand-mark">L</span><div><strong>Laplace</strong><small>System status</small></div></div><a href="/chat">Open chat →</a></div>
    <h1>Local system status</h1><p class="muted">Project: <strong>{name}</strong></p><div class="status-grid"><div class="status-card"><span>Service</span><strong>127.0.0.1</strong><small>Loopback-only</small></div><div class="status-card"><span>Model</span><strong>qwen3:4b</strong><small>One active generation</small></div><div class="status-card"><span>Embeddings</span><strong>qwen3-embedding:0.6b</strong><small>Local Ollama</small></div><div class="status-card"><span>Evidence</span><strong id="doc-count">Loading…</strong><small>Indexed documents</small></div></div><pre id="status-json" class="status-json">Loading project status…</pre></div>
    <script>fetch('/api/project/status').then(r=>r.json()).then(v=>{{document.getElementById('doc-count').textContent=v.documents ?? 0;document.getElementById('status-json').textContent=JSON.stringify(v,null,2)}}).catch(e=>document.getElementById('status-json').textContent='Status unavailable: '+e)</script>
    """
    return _document("Laplace · System status", body)


def _css() -> str:
    return r"""
    :root{--bg:#f7f8fb;--panel:#fff;--ink:#172033;--muted:#718096;--line:#e4e8ef;--accent:#315efb;--accent-soft:#edf1ff;--good:#138a65;--shadow:0 12px 35px rgba(35,48,80,.08)}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--ink);font:14px/1.5 Inter,ui-sans-serif,system-ui,-apple-system,"Segoe UI",sans-serif}.app{min-height:100vh;display:grid;grid-template-columns:265px minmax(420px,1fr) 330px}.sidebar{background:#fff;border-right:1px solid var(--line);padding:22px 16px;display:flex;flex-direction:column;gap:13px}.brand{display:flex;gap:10px;align-items:center;font-size:18px}.brand small{display:block;color:var(--muted);font-size:11px;font-weight:400}.brand-mark,.empty-logo{display:grid;place-items:center;background:linear-gradient(135deg,#4267ee,#8b5cf6);color:#fff;border-radius:11px;width:34px;height:34px;font-weight:800}.project-label,.eyebrow{font-size:10px;letter-spacing:.12em;color:#9aa4b4;font-weight:700}.project-name{font-weight:700;margin-top:-8px}.primary,.send{border:0;background:var(--accent);color:#fff;border-radius:9px;padding:10px 13px;font-weight:700;cursor:pointer}.full{width:100%;text-align:left}.search-input,select,textarea{border:1px solid var(--line);background:#fbfcfe;border-radius:8px;padding:9px;color:var(--ink);font:inherit}.search-input{width:100%}.conversation-list{display:flex;flex-direction:column;gap:3px;max-height:210px;overflow:auto}.conversation-row{display:flex;align-items:center;gap:2px}.conversation-row .conversation{flex:1}.conv-action{border:0;background:transparent;color:#9aa4b4;cursor:pointer;font-size:12px;padding:4px}.conv-action:hover{color:var(--accent)}.conversation{padding:8px 9px;border-radius:8px;cursor:pointer;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.conversation:hover,.conversation.selected{background:var(--accent-soft);color:var(--accent)}.sidebar-section{border-top:1px solid var(--line);padding-top:14px}.collections{display:flex;flex-direction:column;gap:3px}.collection{display:flex;align-items:center;gap:7px;color:#536176;font-size:13px}.mode-label{font-size:11px;color:var(--muted);font-weight:700}.nav{border-top:1px solid var(--line);padding-top:10px;display:grid;gap:2px}.nav a{color:#526078;text-decoration:none;padding:7px 9px;border-radius:7px}.nav a:hover,.nav a.active{background:var(--accent-soft);color:var(--accent);font-weight:700}.privacy{margin-top:auto;border-top:1px solid var(--line);padding-top:12px;color:var(--good);font-size:12px}.privacy span{color:var(--muted);font-size:11px}.main{min-width:0;display:flex;flex-direction:column;min-height:100vh}.topbar{height:76px;background:#fff;border-bottom:1px solid var(--line);padding:17px 32px;display:flex;align-items:center;justify-content:space-between}.topbar h1{font-size:18px;margin:1px 0 0}.top-actions{display:flex;align-items:center;gap:10px}.badge{font-size:11px;background:#effaf6;color:var(--good);padding:5px 9px;border-radius:20px;font-weight:700}.icon-button{border:0;background:transparent;color:#718096;font-size:20px;cursor:pointer}.messages{flex:1;overflow:auto;padding:36px max(24px,8vw) 22px}.empty-state{text-align:center;max-width:640px;margin:12vh auto;color:var(--muted)}.empty-state h2{color:var(--ink);font-size:25px;margin:18px 0 7px}.empty-logo{width:52px;height:52px;margin:auto;border-radius:16px;font-size:22px}.suggestions{display:flex;flex-wrap:wrap;justify-content:center;gap:8px;margin-top:22px}.suggestions button{background:#fff;border:1px solid var(--line);border-radius:18px;padding:8px 12px;color:#536176;cursor:pointer}.message{display:flex;margin:0 0 24px;gap:12px;max-width:850px}.message.user{margin-left:auto;justify-content:flex-end}.avatar{width:28px;height:28px;border-radius:9px;display:grid;place-items:center;background:#e9edff;color:var(--accent);font-weight:800;flex:0 0 auto}.message.user .avatar{order:2;background:#172033;color:#fff}.bubble{background:#fff;border:1px solid var(--line);border-radius:12px;padding:12px 15px;box-shadow:var(--shadow);min-width:80px}.message.user .bubble{background:var(--accent);color:#fff;border:0}.bubble p{margin:0 0 8px}.bubble p:last-child{margin-bottom:0}.bubble ol,.bubble ul{margin:7px 0 5px;padding-left:20px}.citation{display:inline-block;color:var(--accent);background:var(--accent-soft);border:0;border-radius:5px;padding:0 4px;cursor:pointer;font-weight:700}.message.user .citation{color:#fff;background:rgba(255,255,255,.2)}.message-meta{font-size:10px;color:var(--muted);margin-top:6px}.fallback{color:#9a5b08;font-size:11px;margin-top:8px}.status-line{min-height:25px;color:var(--muted);padding:0 max(24px,8vw) 8px;font-size:12px}.composer{background:#fff;border-top:1px solid var(--line);padding:14px max(24px,8vw) 18px}.composer textarea{width:100%;resize:none;background:#fff;min-height:55px}.composer-footer{display:flex;align-items:center;justify-content:space-between;margin-top:8px}.hint{color:#9aa4b4;font-size:11px}.composer-footer>div{display:flex;align-items:center;gap:8px}.secondary{border:1px solid var(--line);background:#fff;color:#b34c4c;border-radius:8px;padding:8px 11px;cursor:pointer}.hidden{display:none}.attach{color:var(--accent);font-size:23px;cursor:pointer}.evidence-panel{background:#fff;border-left:1px solid var(--line);padding:22px 18px;overflow:auto}.panel-heading{display:flex;justify-content:space-between;align-items:center;font-weight:800;font-size:15px}.evidence-empty{color:var(--muted);text-align:center;margin-top:35vh;font-size:13px}.evidence-card{border-top:1px solid var(--line);margin-top:18px;padding-top:15px}.evidence-card h3{font-size:14px;margin:0 0 4px}.evidence-card .tag{display:inline-block;font-size:10px;background:#f0f3f8;color:#536176;border-radius:4px;padding:3px 6px;margin:3px 3px 7px 0}.quote{border-left:3px solid #a8b8ff;padding-left:10px;color:#4e5b70;font-size:13px}.secondary-page{flex:1;overflow:auto;padding:34px max(24px,8vw)}.secondary-card{background:#fff;border:1px solid var(--line);border-radius:12px;padding:18px;margin-bottom:14px;box-shadow:var(--shadow)}.secondary-card h2{margin-top:0}.secondary-card button{border:0;background:var(--accent);color:#fff;border-radius:7px;padding:8px 11px;cursor:pointer}.secondary-card textarea{width:100%;min-height:220px}.secondary-row{display:flex;justify-content:space-between;border-bottom:1px solid var(--line);padding:10px 0}.dashboard{max-width:1080px;margin:auto;padding:32px}.dashboard-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:60px}.dashboard-header a{color:var(--accent);text-decoration:none;font-weight:700}.dashboard h1{font-size:30px}.muted{color:var(--muted)}.status-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin:25px 0}.status-card{background:#fff;border:1px solid var(--line);border-radius:12px;padding:17px;box-shadow:var(--shadow)}.status-card span,.status-card small{display:block;color:var(--muted);font-size:11px}.status-card strong{display:block;font-size:19px;margin:7px 0}.status-json{background:#172033;color:#dbe5ff;border-radius:10px;padding:17px;overflow:auto}@media(max-width:1050px){.app{grid-template-columns:230px minmax(350px,1fr)}.evidence-panel{display:none}.status-grid{grid-template-columns:repeat(2,1fr)}}@media(max-width:700px){.app{display:block}.sidebar{position:relative;border-right:0;border-bottom:1px solid var(--line);padding:13px;gap:8px}.conversation-list,.sidebar-section,.mode-label,select,.privacy{display:none}.nav{display:flex;overflow:auto;border-top:0;padding:0}.nav a{white-space:nowrap}.main{min-height:calc(100vh - 92px)}.topbar{padding:14px 17px}.messages{padding:25px 15px}.composer{padding:11px 15px}.hint{display:none}.status-grid{grid-template-columns:1fr}.dashboard{padding:20px}}
    """


def _js() -> str:
    return r"""
    (()=>{const $=s=>document.querySelector(s), state={conversation:null,conversations:[],citations:[]};
    const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
    const md=s=>{let t=esc(s);t=t.replace(/```([\s\S]*?)```/g,'<pre><code>$1</code></pre>').replace(/^### (.*)$/gm,'<h4>$1</h4>').replace(/^## (.*)$/gm,'<h3>$1</h3>').replace(/^# (.*)$/gm,'<h2>$1</h2>').replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>').replace(/`([^`]+)`/g,'<code>$1</code>').replace(/\n\n/g,'</p><p>').replace(/\n/g,'<br>');return '<p>'+t+'</p>'};
    const status=m=>{$('#status-line').textContent=m||''};
    async function api(url,opt){const r=await fetch(url,{headers:{'Content-Type':'application/json',...(opt?.headers||{})},...opt});if(!r.ok)throw new Error(await r.text());return r.json()}
    function addMessage(role,content,citations=[],fallback=false){const wrap=document.createElement('div');wrap.className='message '+role;let html=md(content);(citations||[]).forEach(c=>{const n=c.citation_id;html=html.replaceAll('['+n+']','<button class="citation" data-citation="'+n+'">['+n+']</button>')});wrap.innerHTML='<div class="avatar">'+(role==='user'?'You':'L')+'</div><div><div class="bubble">'+html+(fallback?'<div class="fallback">Grounded extractive fallback · model citation rejected</div>':'')+'</div></div>';$('#messages').appendChild(wrap);wrap.querySelectorAll('.citation').forEach(b=>b.onclick=()=>showEvidence(citations[Number(b.dataset.citation)-1]));$('#messages').scrollTop=$('#messages').scrollHeight;return wrap}
    function showEvidence(c){if(!c)return;$('#evidence-content').innerHTML='<div class="evidence-card"><h3>['+c.citation_id+'] '+esc(c.title||c.filename)+'</h3><span class="tag">'+esc(c.source_class)+'</span><span class="tag">'+esc(c.availability)+'</span><span class="tag">p. '+esc(c.page??'—')+'</span><span class="tag">score '+Number(c.score||0).toFixed(3)+'</span><p><strong>File:</strong> '+esc(c.filename)+'</p><p><strong>Chunk:</strong> <code>'+esc(c.chunk_id)+'</code></p><p><strong>Section:</strong> '+esc(c.section||'—')+'</p><p class="quote">'+esc(c.quoted_evidence)+'</p></div>'}
    async function loadConversations(){const v=await api('/api/chat/conversations');state.conversations=v.conversations||[];const list=$('#conversation-list');list.innerHTML='';state.conversations.forEach(c=>{const row=document.createElement('div');row.className='conversation-row';const e=document.createElement('div');e.className='conversation '+(state.conversation?.conversation_id===c.conversation_id?'selected':'');e.textContent=c.title;e.onclick=()=>openConversation(c.conversation_id);const rename=document.createElement('button');rename.className='conv-action';rename.textContent='✎';rename.title='Rename';rename.onclick=async ev=>{ev.stopPropagation();const title=prompt('Conversation name',c.title);if(title)await api('/api/chat/conversations/'+c.conversation_id,{method:'PATCH',body:JSON.stringify({title})});loadConversations()};const archive=document.createElement('button');archive.className='conv-action';archive.textContent='×';archive.title='Archive';archive.onclick=async ev=>{ev.stopPropagation();await api('/api/chat/conversations/'+c.conversation_id,{method:'PATCH',body:JSON.stringify({archived:true})});loadConversations()};row.append(e,rename,archive);list.appendChild(row)})}
    async function loadCollections(){const v=await api('/api/project/collections');$('#collections').innerHTML=(v.collections||[]).map(c=>'<label class="collection"><input type="checkbox" value="'+esc(c.name)+'" '+(c.selected?'checked':'')+'> '+esc(c.name)+' <small>('+esc(c.documents)+')</small></label>').join('')}
    function selectedCollections(){return Array.from(document.querySelectorAll('#collections input:checked')).map(x=>x.value)}
    async function newConversation(){state.conversation=await api('/api/chat/conversations',{method:'POST',body:JSON.stringify({title:'New chat',collections:selectedCollections().length?selectedCollections():['MyWorks'],mode:$('#mode').value})});$('#messages').innerHTML='';$('#conversation-title').textContent=state.conversation.title;await loadConversations()}
    async function openConversation(id){const v=await api('/api/chat/conversations/'+id);state.conversation=v;$('#conversation-title').textContent=v.title;$('#messages').innerHTML='';(v.messages||[]).forEach(m=>addMessage(m.role,m.content,m.citations,m.fallback_used));await loadConversations()}
    async function ensureConversation(){if(!state.conversation)await newConversation()}
    async function send(){const box=$('#prompt'),text=box.value.trim();if(!text)return;await ensureConversation();box.value='';addMessage('user',text);$('#stop').classList.remove('hidden');status('Searching local collections…');let assistant=null;try{const r=await fetch('/api/chat/conversations/'+state.conversation.conversation_id+'/messages?stream=true',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({content:text,mode:$('#mode').value,collections:selectedCollections().length?selectedCollections():['MyWorks']})});if(!r.ok)throw new Error(await r.text());const reader=r.body.getReader(),decoder=new TextDecoder(),bubble=addMessage('assistant','',[]);let buffer='',content='';while(true){const x=await reader.read();if(x.done)break;buffer+=decoder.decode(x.value,{stream:true});const parts=buffer.split('\n\n');buffer=parts.pop();for(const part of parts){if(!part.startsWith('data:'))continue;const e=JSON.parse(part.slice(5).trim());if(e.type==='retrieval_result')status('Retrieved '+e.count+' passages…');if(e.type==='status')status(e.message);if(e.type==='token'){content+=e.text;bubble.querySelector('.bubble').innerHTML=md(content)}if(e.type==='message_completed'){assistant=e.message;content=assistant.content;bubble.remove();addMessage('assistant',content,assistant.citations,assistant.fallback_used);status(assistant.status+' · '+assistant.citations.length+' citations')}if(e.type==='message_failed')throw new Error(e.error)}}}catch(e){status('Error: '+e.message)}finally{$('#stop').classList.add('hidden');await loadConversations()}}
    $('#new-chat').onclick=newConversation;$('#composer').onsubmit=e=>{e.preventDefault();send()};$('#prompt').onkeydown=e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();send()}};$('#attachment').onchange=async e=>{const file=e.target.files[0];if(!file)return;await ensureConversation();const form=new FormData();form.append('file',file);const r=await fetch('/api/chat/conversations/'+state.conversation.conversation_id+'/attachments',{method:'POST',body:form});status(r.ok?'Attachment staged for this project.':'Attachment rejected: '+await r.text());e.target.value=''};$('#stop').onclick=async()=>{if(state.conversation)await api('/api/chat/conversations/'+state.conversation.conversation_id+'/stop',{method:'POST'});status('Stop requested…')};$('#close-evidence').onclick=()=>{$('#evidence-content').innerHTML='<div class="evidence-empty">Select a citation to inspect its retrieved passage.</div>'};$('#export').onclick=()=>{if(state.conversation)window.open('/api/chat/conversations/'+state.conversation.conversation_id+'/export','_blank')};document.querySelectorAll('[data-suggestion]').forEach(b=>b.onclick=()=>{$('#prompt').value=b.dataset.suggestion;send()});$('#conversation-filter').oninput=e=>{document.querySelectorAll('.conversation').forEach(x=>x.style.display=x.textContent.toLowerCase().includes(e.target.value.toLowerCase())?'':'none')};loadConversations().catch(e=>status(e.message));
    async function setupPage(){const page=$('.app').dataset.page;if(page==='/chat')return;$('#messages').classList.add('hidden');$('#composer').classList.add('hidden');$('#evidence-panel').classList.add('hidden');const panel=$('#secondary-page');panel.classList.remove('hidden');if(page==='/library'){panel.innerHTML='<div class="secondary-card"><h2>Library</h2><p class="muted">Indexed collections and provenance status.</p><div id="collection-status">Loading…</div></div>';const v=await api('/api/project/collections');$('#collection-status').innerHTML=(v.collections||[]).map(c=>'<div class="secondary-row"><span>'+esc(c.name)+'</span><strong>'+esc(c.documents)+' documents</strong></div>').join('')}else if(page==='/research'){panel.innerHTML='<div class="secondary-card"><h2>Research</h2><p class="muted">Search configured scholarly metadata providers. Candidates remain separate from local evidence until downloaded and ingested.</p><input id="research-query" class="search-input" placeholder="Search scholarly providers"><button id="research-go">Search</button><div id="research-results"></div></div>';$('#research-go').onclick=async()=>{const q=$('#research-query').value.trim();if(!q)return;$('#research-results').textContent='Searching…';const v=await api('/api/search/scholarly?query='+encodeURIComponent(q));$('#research-results').innerHTML=(v.results||[]).slice(0,10).map(x=>'<div class="secondary-row"><span>'+esc(x.title||'Untitled')+'</span><small>'+esc(x.access_level||x.availability||'metadata')+'</small></div>').join('')||'No results.'}}else if(page==='/downloads'){panel.innerHTML='<div class="secondary-card"><h2>Downloads</h2><p class="muted">Project-local open-access and IEEE workflow files. Promotion always requires explicit confirmation.</p><div id="download-status">Loading…</div></div>';const v=await api('/api/project/status');$('#download-status').innerHTML='<div class="secondary-row"><span>Downloaded PDFs</span><strong>'+esc(v.downloads||0)+'</strong></div><div class="secondary-row"><span>Indexed documents</span><strong>'+esc(v.documents||0)+'</strong></div>'}else if(page==='/settings'){panel.innerHTML='<div class="secondary-card"><h2>Settings</h2><p class="muted">Project instructions and retrieval settings. Secrets are never returned.</p><select id="settings-file"><option>instructions.md</option><option>writing_style.yaml</option><option>retrieval.yaml</option><option>providers.yaml</option></select><textarea id="settings-content"></textarea><button id="settings-save">Save with backup</button><span id="settings-status"></span></div>';const v=await api('/api/project/settings');const load=()=>{$('#settings-content').value=(v.settings||{})[$('#settings-file').value]||''};$('#settings-file').onchange=load;load();$('#settings-save').onclick=async()=>{const name=$('#settings-file').value;const out=await api('/api/project/settings/'+name,{method:'PATCH',body:JSON.stringify({content:$('#settings-content').value})});$('#settings-status').textContent=' '+out.status+' · backup created'}}}
    setupPage().catch(e=>status(e.message));
    loadCollections().catch(e=>status(e.message));
    })();
    """
